 1	import { K8sResourceCondition, K8sResourceKind } from '@openshift-console/dynamic-plugin-sdk';
 2	import { Button, Text, TextVariants } from '@patternfly/react-core';
 3	import { Table, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
 4	import React, { FC } from 'react';
 5	import { useTranslation } from 'react-i18next';
 6	import { useNavigate } from '../../utils/url';
 7	
 8	export type ResourceStatusProps = {
 9	  group: string;
10	  version: string;
11	  kind: string;
12	  existing: K8sResourceKind | null;
13	  selectedTypes: string[];
14	  setSelectedTypes: (types: string[]) => void;
15	};
16	
17	export const ResourceStatus: FC<ResourceStatusProps> = ({
18	  group,
19	  version,
20	  kind,
21	  existing,
22	  selectedTypes,
23	  setSelectedTypes
24	}) => {
25	  const { t } = useTranslation('plugin__netobserv-plugin');
26	  const navigate = useNavigate();
27	
28	  if (!existing) {
29	    return (
30	      <>
31	        <Text component={TextVariants.p}>{t("{{kind}} resource doesn't exists yet.", { kind })}</Text>
32	        <Button
33	          onClick={() => {
34	            navigate(`/k8s/cluster/${group}~${version}~${kind}/~new/form`);
35	          }}
36	        >
37	          {t('Create {{kind}}', { kind })}
38	        </Button>
39	      </>
40	    );
41	  }
42	
43	  const sortConditions = [
44	    // 1. Global Ready
45	    (c: K8sResourceCondition) => c.type === 'Ready',
46	    // 2. Used components / conditions
47	    (c: K8sResourceCondition) => c.reason !== 'ComponentUnused'
48	    // 3. Others (unused components)
49	  ];
50	  const conditions = ((existing?.status?.conditions || []) as K8sResourceCondition[]).sort((a, b) => {
51	    for (const pred of sortConditions) {
52	      if (pred(a) && pred(b)) {
53	        return 0;
54	      } else if (pred(a)) {
55	        return -1;
56	      } else if (pred(b)) {
57	        return 1;
58	      }
59	    }
60	    return 0;
61	  });
62	  return (
63	    <Table id="resource-status-table" data-test={conditions.find(c => c.type === 'Ready')?.message} variant={'compact'}>
64	      <Thead>
65	        <Tr>
66	          <Th>{t('Type')}</Th>
67	          <Th>{t('Status')}</Th>
68	          <Th>{t('Reason')}</Th>
69	          <Th>{t('Message')}</Th>
70	          <Th>{t('Changed')}</Th>
71	        </Tr>
72	      </Thead>
73	      <Tbody>
74	        {conditions.map((condition, i) => (
75	          <Tr
76	            id={`${condition.type}-row`}
77	            data-test-status={`${condition.status}`}
78	            data-test-reason={`${condition.reason}`}
79	            key={i}
80	            isRowSelected={selectedTypes.includes(condition.type)}
81	            onClick={() => setSelectedTypes([condition.type])}
82	          >
83	            <Td>{condition.type}</Td>
84	            <Td>{condition.status}</Td>
85	            <Td>{condition.reason}</Td>
86	            <Td>{condition.message}</Td>
87	            <Td>{condition.lastTransitionTime}</Td>
88	          </Tr>
89	        ))}
90	      </Tbody>
91	    </Table>
92	  );
93	};
94	
95	export default ResourceStatus;

